features.snippet:
genvar r,c;
for(r=0;r<4;r++) begin:PER
  for(c=0;c<8;c++) begin:PEC
    pe #(.WX(4),.WK(8),.WY(16),.LM(1),.LA(1)) PE (...);
  end
end

module mac #(parameter WX=4,WK=8,WY=16,LM=1,LA=1, localparam WM=WX+WK)(input wire clk,...);
  n_delay #(.N(LA-1),.W(WY)) ad(...);
endmodule
module pe #(...)(...);
  mac #(.WX(WX),.WK(WK),.WY(WY),.LM(LM),.LA(LA)) MAC (...);
